private ArrayList<Long> getIdsOfMatchingStringFields(String lowerCaseSearch) {
		ArrayList<Long> ids = new ArrayList<>();
		long numOrders = orderHeaderRepository.count();
		int page = 0;
		int batchSize = 50;
		int totalPages = (int) Math.ceil( (double)numOrders / batchSize );
		do {
			log.debug("Processing orders page {} of {}", page, totalPages);
			em.clear();

			Page<OrderHeaderProjection> fields = orderHeaderRepository.findAllProjectedBy(PageRequest.of(page, batchSize));
			fields.forEach(field -> {
				String buyerName = field.getBuyerName() == null ? "" : field.getBuyerName().toLowerCase();
				String buyerEmail = field.getBuyerEmail() == null ? "" : field.getBuyerEmail().toLowerCase();
				if (buyerName.contains(lowerCaseSearch) || buyerEmail.contains(lowerCaseSearch)) {
					ids.add(field.getId());
				}
			});
			page++;
			log.debug("Found {} orders matching search string out of {}", ids.size(), numOrders);
		} while ((long) page *batchSize < numOrders);
		return ids;
	}
